#' Calculate Classification Metrics Using `caret`'s Confusion Matrix
#'
#' This function calculates common classification metrics such as accuracy, sensitivity, specificity,
#' positive predictive value (PPV), negative predictive value (NPV), F1 score, and prevalence based on
#' the confusion matrix generated by the `caret` package.
#'
#' @import caret
#' @param predictions A vector of predicted class labels from the model.
#' @param groups A vector of true class labels (ground truth) for the samples.
#' @param levels A character vector of the class labels (levels) for the model, where the first element
#' is the class of interest (positive class).
#' @param prevalence A numeric value indicating the prevalence of the positive class in the dataset.
#' If NULL, the prevalence will be taken from the confusion matrix.
#'
#' @returns A data frame with the calculated metrics:
#' \item{Accuracy}{The overall accuracy of the classification model.}
#' \item{Sensitivity}{The true positive rate (recall or true positive rate).}
#' \item{Specificity}{The true negative rate.}
#' \item{Prevalence}{The proportion of positive cases in the dataset.}
#' \item{PPV}{Positive Predictive Value (Precision).}
#' \item{NPV}{Negative Predictive Value.}
#' \item{F1_Score}{The F1 score, which is the harmonic mean of precision and recall.}
#'
#' @export
#'
#' @examples
#' \dontrun{
#' # Example usage:
#' predictions <- c(1, 0, 1, 0, 1, 1)
#' groups <- c(1, 0, 0, 1, 1, 0)
#' levels <- c(0, 1)  # Negative class is 0, positive class is 1
#' metrics <- calculate_metrics_caret(predictions, groups, levels)
#' print(metrics)
#' }

calculate_metrics_caret <- function(predictions,
                                    groups,
                                    levels,
                                    prevalence = NULL) {
  if (is.null(prevalence)) {
    conf_matrix <- confusionMatrix(factor(predictions, levels = rev(levels)),
                                   factor(groups, levels = rev(levels)))
    print(conf_matrix)
    accuracy <- sum(diag(conf_matrix$table)) / sum(conf_matrix$table)
    sensitivity <- conf_matrix$byClass['Sensitivity']
    specificity <- conf_matrix$byClass['Specificity']
    ppv <- conf_matrix$byClass['Pos Pred Value']
    npv <- conf_matrix$byClass['Neg Pred Value']
    f1 <- conf_matrix$byClass['F1']
    prevalence <- conf_matrix$byClass['Prevalence']
  } else {
    conf_matrix <- confusionMatrix(factor(predictions, levels = rev(levels)),
                                   factor(groups, levels = rev(levels)),
                                   prevalence = prevalence)
    print(conf_matrix)
    accuracy <- sum(diag(conf_matrix$table)) / sum(conf_matrix$table)
    sensitivity <- conf_matrix$byClass['Sensitivity']
    specificity <- conf_matrix$byClass['Specificity']
    ppv <- conf_matrix$byClass['Pos Pred Value']
    npv <- conf_matrix$byClass['Neg Pred Value']
    f1 <- conf_matrix$byClass['F1']
    prevalence <- prevalence
  }

  metrics <- data.frame(
    Accuracy = accuracy,
    Sensitivity = sensitivity,
    Specificity = specificity,
    Prevalence = prevalence,
    PPV = ppv,
    NPV = npv,
    F1_Score = f1
  )

  return(metrics)
}



#' Calculate Classification Metrics for Various Thresholds
#'
#' This function calculates classification metrics (accuracy, positive predictive value (PPV),
#' and negative predictive value (NPV)) for a range of threshold values. The thresholds are
#' determined based on the unique predicted values, and the metrics are calculated by applying
#' each threshold to the predictions.
#'
#' @param predicted_values A numeric vector of predicted probabilities or continuous values
#' from the model, which will be thresholded to generate predicted class labels.
#' @param groups A vector of true class labels (ground truth) for the samples.
#' @param levels A character vector of the class labels (levels) for the model, where the first element
#' is the class of interest (positive class) and the second element is the negative class.
#'
#' @returns A data frame with calculated metrics for each threshold:
#' \item{Threshold}{The threshold value used to classify the predicted values.}
#' \item{Accuracy}{The overall accuracy of the classification model for the given threshold.}
#' \item{PPV}{Positive Predictive Value (Precision) for the given threshold.}
#' \item{NPV}{Negative Predictive Value for the given threshold.}
#'
#' @export
#'
#' @examples
#' \dontrun{
#' # Example usage:
#' predicted_values <- c(0.9, 0.7, 0.6, 0.8, 0.4, 0.2)
#' groups <- c(1, 0, 1, 0, 1, 0)
#' levels <- c(1, 0)  # Positive class is 1, negative class is 0
#' metrics_results <- calculate_metrics_for_thresholds(predicted_values, groups, levels)
#' print(metrics_results)
#' }

calculate_metrics_for_thresholds <- function(predicted_values,
                                             groups,
                                             levels) {

  thresholds <- sort(unique(predicted_values), decreasing = TRUE)


  results <- data.frame(Threshold = numeric(0), Accuracy = numeric(0), PPV = numeric(0), NPV = numeric(0))

  positive_class <- levels[1]
  negative_class <- levels[2]
  cat("Positive Class:", positive_class, "\n")
  cat("Negative Class:", negative_class, "\n")
  for (threshold in thresholds) {
    predictions <- ifelse(predicted_values >= threshold, positive_class, negative_class)

    metrics <- calculate_metrics_caret(predictions, groups, levels)

    results <- rbind(results, data.frame(Threshold = threshold,
                                         Accuracy = metrics$Accuracy,
                                         PPV = metrics$PPV,
                                         NPV = metrics$NPV))
  }

  return(results)
}


#' Plot Accuracy vs Threshold Curve
#'
#' This function generates a plot showing the relationship between classification accuracy
#' and different threshold values. The plot highlights the threshold with the maximum accuracy
#' and annotates it on the graph.
#'
#' @import ggplot2
#' @import wesanderson
#' @param threshold_metrics A data frame containing the threshold values and corresponding
#' accuracy metrics. The data frame must have at least two columns: 'Threshold' and 'Accuracy'.
#' @param title A character string specifying the title of the plot. Default is "Accuracy vs Threshold".
#' @param theme A ggplot2 theme object for customizing the plot appearance. Default is `theme_scp()`.
#' @param palette_name A character string specifying the color palette for the plot. Default is "Zissou1".
#' @param base_size An integer specifying the base font size for the plot elements. Default is 14.
#' @param save_plots A logical value indicating whether to save the plot. Default is TRUE.
#' @param save_dir A character string specifying the directory where the plot will be saved.
#' Default is `"ModelData/best_model_result"`.
#' @param plot_width An integer specifying the width of the saved plot in inches. Default is 5.
#' @param plot_height An integer specifying the height of the saved plot in inches. Default is 5.
#'
#' @returns A list containing:
#' \item{plot}{The ggplot2 object of the accuracy vs threshold plot.}
#' \item{threshold}{The threshold value corresponding to the maximum accuracy.}
#'
#' @export
#'
#' @examples
#' \dontrun{
#' # Example usage:
#' threshold_metrics <- data.frame(Threshold = seq(0, 1, by = 0.05),
#'                                  Accuracy = runif(21, 0.5, 1))
#' plot_results <- plot_accuracy_vs_threshold(threshold_metrics)
#' }

plot_accuracy_vs_threshold <- function(threshold_metrics,
                                       title = "Accuracy vs Threshold",
                                       theme = theme_scp(),
                                       palette_name = "Zissou1",
                                       base_size = 14,
                                       save_plots = TRUE,
                                       save_dir = here("ModelData", "best_model_result"),
                                       plot_width = 5,
                                       plot_height = 5) {

  max_accuracy_row <- threshold_metrics[which.max(threshold_metrics$Accuracy), ]
  max_threshold <- max_accuracy_row$Threshold
  max_accuracy <- max_accuracy_row$Accuracy
  colors <- wes_palette(palette_name, type = "discrete")

  p <- ggplot(threshold_metrics, aes(x = Threshold, y = Accuracy)) +
    geom_line(color = colors[1], size = 1) +
    geom_point(x = max_threshold, y = max_accuracy, color = "red", size = 4, shape = 18) +
    annotate("text", x = max_threshold, y = max_accuracy,
             label = paste0('Max Accuracy: ', round(max_accuracy, 2),
                            '\nThreshold: ', round(max_threshold, 2)),
             vjust = -1.5, color = "red", size = 4, fontface = "bold") +
    labs(title = title,
         x = "Threshold",
         y = "Accuracy") +
    theme_minimal(base_size = base_size) +
    theme(
      plot.title = element_text(size = base_size + 2, face = "bold", hjust = 0.5),
      axis.title = element_text(size = base_size, face = "bold"),
      axis.text = element_text(size = base_size - 2),
      panel.grid.major = element_line(color = "#d9d9d9", linetype = "dashed"),
      panel.grid.minor = element_blank(),
      panel.background = element_rect(fill = "#f0f0f0", color = NA)
    ) +
    theme

  if (save_plots) {
    ggsave(filename = file.path(save_dir, "accuracy_vs_threshold_curve.pdf"),
           plot = p,
           width = plot_width, height = plot_height,
           device = "pdf")
    cat("Plot saved to:", file.path(save_dir, "accuracy_vs_threshold_curve.pdf"), "\n")
  }

  return(list(plot = p, threshold = max_threshold))
}

#' Plot PPV vs Threshold Curve (Closest to 0.95)
#'
#' This function generates a plot showing the relationship between the positive predictive
#' value (PPV) and different threshold values. The plot highlights the threshold that gives
#' the PPV closest to 0.95 and annotates it on the graph.
#'
#' @import ggplot2
#' @import wesanderson
#' @param threshold_metrics A data frame containing the threshold values and corresponding
#' PPV metrics. The data frame must have at least two columns: 'Threshold' and 'PPV'.
#' @param title A character string specifying the title of the plot. Default is "PPV vs Threshold (Closest to 0.95)".
#' @param theme A ggplot2 theme object for customizing the plot appearance. Default is `theme_scp()`.
#' @param palette_name A character string specifying the color palette for the plot. Default is "Zissou1".
#' @param base_size An integer specifying the base font size for the plot elements. Default is 14.
#' @param save_plots A logical value indicating whether to save the plot. Default is TRUE.
#' @param save_dir A character string specifying the directory where the plot will be saved.
#' Default is `"ModelData/best_model_result"`.
#' @param plot_width An integer specifying the width of the saved plot in inches. Default is 5.
#' @param plot_height An integer specifying the height of the saved plot in inches. Default is 5.
#'
#' @returns A list containing:
#' \item{plot}{The ggplot2 object of the PPV vs threshold plot.}
#' \item{threshold}{The threshold value that gives the PPV closest to 0.95.}
#'
#' @export
#'
#' @examples
#' \dontrun{
#' # Example usage:
#' threshold_metrics <- data.frame(Threshold = seq(0, 1, by = 0.05),
#'                                  PPV = runif(21, 0.5, 1))
#' plot_results <- plot_ppv_vs_threshold(threshold_metrics)
#' }

plot_ppv_vs_threshold <- function(threshold_metrics,
                                  title = "PPV vs Threshold (Closest to 0.95)",
                                  theme = theme_scp(),
                                  palette_name = "Zissou1",
                                  base_size = 14,
                                  save_plots = TRUE,
                                  save_dir = here("ModelData", "best_model_result"),
                                  plot_width = 5,
                                  plot_height = 5) {

  closest_ppv_row <- threshold_metrics[which.min(abs(threshold_metrics$PPV - 0.95)), ]
  closest_ppv_threshold <- closest_ppv_row$Threshold
  closest_ppv <- closest_ppv_row$PPV

  colors <- wes_palette(palette_name, type = "discrete")

  p <- ggplot(threshold_metrics, aes(x = Threshold, y = PPV)) +
    geom_line(color = colors[1], size = 1) +
    geom_point(x = closest_ppv_threshold, y = closest_ppv, color = "red", size = 4, shape = 18) +
    annotate("text", x = closest_ppv_threshold, y = closest_ppv,
             label = paste0('Closest PPV to 0.95: ', round(closest_ppv, 2),
                            '\nThreshold: ', round(closest_ppv_threshold, 2)),
             vjust = -1.5, color = "red", size = 4, fontface = "bold") +
    labs(title = title,
         x = "Threshold",
         y = "PPV") +
    theme_minimal(base_size = base_size) +
    theme(
      plot.title = element_text(size = base_size + 2, face = "bold", hjust = 0.5),
      axis.title = element_text(size = base_size, face = "bold"),
      axis.text = element_text(size = base_size - 2),
      panel.grid.major = element_line(color = "#d9d9d9", linetype = "dashed"),
      panel.grid.minor = element_blank(),
      panel.background = element_rect(fill = "#f0f0f0", color = NA)
    ) +
    theme

  if (save_plots) {
    ggsave(filename = file.path(save_dir, "ppv_vs_threshold_closest_to_0.95.pdf"),
           plot = p,
           width = plot_width, height = plot_height,device = "pdf")
    cat("Plot saved to:", file.path(save_dir, "ppv_vs_threshold_closest_to_0.95.pdf"), "\n")
  }

  return(list(plot = p, threshold = closest_ppv_threshold))
}


