#' Select the Best Threshold Based on a Given Method
#'
#' This function selects the best threshold for model performance based on one of the
#' specified methods. It generates the corresponding plot (Accuracy vs Threshold,
#' PPV vs Threshold, or NPV vs Threshold) and annotates the best threshold on the plot.
#'
#' @param threshold_metrics A data frame containing the threshold values and corresponding
#' performance metrics (e.g., Accuracy, PPV, NPV). The data frame must contain at least
#' columns for 'Threshold', 'Accuracy', 'PPV', and 'NPV'.
#' @param method_threshold A character string specifying the method for selecting the best threshold.
#' It can be one of: "max_accuracy", "closest_ppv", or "closest_npv". Default is "max_accuracy".
#' @param title A character string specifying the title of the plot. If `NULL`, a default title
#' will be used based on the method selected. Default is `NULL`.
#' @param theme A ggplot2 theme object for customizing the plot appearance. Default is `theme_scp()`.
#' @param palette_name A character string specifying the color palette for the plot. Default is "Zissou1".
#' @param base_size An integer specifying the base font size for the plot elements. Default is 14.
#' @param save_plots A logical value indicating whether to save the plot. Default is TRUE.
#' @param save_dir A character string specifying the directory where the plot will be saved.
#' Default is `"ModelData/best_model_result"`.
#' @param plot_width An integer specifying the width of the saved plot in inches. Default is 5.
#' @param plot_height An integer specifying the height of the saved plot in inches. Default is 5.
#'
#' @returns A list containing:
#' \item{plot}{The ggplot2 object of the performance vs threshold plot.}
#' \item{threshold}{The best threshold selected based on the chosen method.}
#'
#' @export
#'
#' @examples
#' \dontrun{
#' # Example usage:
#' threshold_metrics <- data.frame(Threshold = seq(0, 1, by = 0.05),
#'                                  Accuracy = runif(21, 0.5, 1),
#'                                  PPV = runif(21, 0.5, 1),
#'                                  NPV = runif(21, 0.5, 1))
#' result <- select_best_threshold(threshold_metrics, method_threshold = "max_accuracy")
#' }

select_best_threshold <- function(threshold_metrics,
                                  method_threshold = c("max_accuracy", "closest_ppv", "closest_npv"),
                                  title = NULL,
                                  theme = theme_scp(),
                                  palette_name = "Zissou1",
                                  base_size = 14,
                                  save_plots = TRUE,
                                  save_dir = here("ModelData", "best_model_result"),
                                  plot_width = 5,
                                  plot_height = 5) {

  method_threshold <- match.arg(method_threshold)

  if (method_threshold == "max_accuracy") {
    result <- plot_accuracy_vs_threshold(
      threshold_metrics = threshold_metrics,
      title = ifelse(is.null(title), "Accuracy vs Threshold", title),
      theme = theme,
      palette_name = palette_name,
      base_size = base_size,
      save_plots = save_plots,
      save_dir = save_dir,
      plot_width = plot_width,
      plot_height = plot_height
    )
  } else if (method_threshold == "closest_ppv") {
    result <- plot_ppv_vs_threshold(
      threshold_metrics = threshold_metrics,
      title = ifelse(is.null(title), "PPV vs Threshold (Closest to 0.95)", title),
      theme = theme,
      palette_name = palette_name,
      base_size = base_size,
      save_plots = save_plots,
      save_dir = save_dir,
      plot_width = plot_width,
      plot_height = plot_height
    )
  } else if (method_threshold == "closest_npv") {
    result <- plot_npv_vs_threshold(
      threshold_metrics = threshold_metrics,
      title = ifelse(is.null(title), "NPV vs Threshold (Closest to 0.95)", title),
      theme = theme,
      palette_name = palette_name,
      base_size = base_size,
      save_plots = save_plots,
      save_dir = save_dir,
      plot_width = plot_width,
      plot_height = plot_height
    )
  }
  cat("Best threshold:", result$threshold, "\n")

  return(result)
}

#' Model Threshold Selection and Update for Model_data Object
#'
#' This function selects the best threshold for model performance based on the specified
#' method, and updates the input `Model_data` object with the selected threshold and
#' associated metrics. The function predicts probabilities using the model in the
#' `Model_data` object, calculates the corresponding threshold metrics, and selects
#' the best threshold using one of the provided methods ("max_accuracy", "closest_ppv",
#' or "closest_npv"). The function also generates and saves relevant plots if desired.
#'
#' @importFrom SCP theme_scp
#' @param object An object of class 'Model_data', which contains the model and other necessary data.
#' @param group_col A character string specifying the name of the column representing the group
#' (or class) in the testing dataset. Default is "group".
#' @param threshold_metrics A data frame containing threshold metrics (e.g., Accuracy, PPV, NPV)
#' calculated for different thresholds. If `NULL`, the metrics will be calculated within the function.
#' @param method_threshold A character string specifying the method for selecting the best threshold.
#' It can be one of: "max_accuracy", "closest_ppv", or "closest_npv". Default is "max_accuracy".
#' @param title A character string specifying the title of the plot. If `NULL`, a default title
#' will be used based on the method selected. Default is `NULL`.
#' @param theme A ggplot2 theme object for customizing the plot appearance. Default is `theme_scp()`.
#' @param palette_name A character string specifying the color palette for the plot. Default is "Zissou1".
#' @param base_size An integer specifying the base font size for the plot elements. Default is 14.
#' @param save_plots A logical value indicating whether to save the plot. Default is TRUE.
#' @param save_dir A character string specifying the directory where the plot will be saved.
#' Default is `"ModelData/best_model_result"`.
#' @param plot_width An integer specifying the width of the saved plot in inches. Default is 5.
#' @param plot_height An integer specifying the height of the saved plot in inches. Default is 5.
#'
#' @returns An updated `Model_data` object with the best threshold and associated information
#' stored in the `best.model.result` slot.
#'
#' @export
#'
#' @examples
#' \dontrun{
#' # Example usage:
#' model_data_object <- ModelThreshold(object = model_data_object,
#'                                     method_threshold = "max_accuracy")
#' }
ModelThreshold <- function(object,
                           group_col = "group",
                           threshold_metrics = NULL,
                           method_threshold = c("max_accuracy", "closest_ppv", "closest_npv"),
                           title = NULL,
                           theme = theme_scp(),
                           palette_name = "Zissou1",
                           base_size = 14,
                           save_plots = TRUE,
                           save_dir = here("ModelData", "best_model_result"),
                           plot_width = 5,
                           plot_height = 5) {

  cat("Starting ModelThreshold function...\n")

  if (!inherits(object, "Model_data")) {
    stop("Input must be an object of class 'Model_data'")
  }

  cat("Input is of class 'Model_data'. Proceeding with data extraction...\n")

  model <- object@best.model.result[["model"]]
  group_col <- object@group_col
  data_sets <- Extract_filtered.set(object)
  test_data <- data_sets$testing
  cat("Data extraction completed. Predicting values...\n")

  predicted_values <- predict(model, newdata = test_data, type = "prob")[, 2]
  truth <- test_data[[group_col]]
  test_data[[group_col]] <- factor(test_data[[group_col]])
  lvs <- levels(test_data[[group_col]])
  test_data$pred_prob <- predicted_values

  cat("Prediction completed. Calculating threshold metrics...\n")

  if (is.null(threshold_metrics)) {
    threshold_metrics <- calculate_metrics_for_thresholds(
      predicted_values = predicted_values,
      groups = truth,
      levels = lvs
    )
  }

  cat("Threshold metrics calculated. Selecting best threshold...\n")

  result <- select_best_threshold(
    threshold_metrics = threshold_metrics,
    method_threshold = method_threshold,
    title = title,
    theme = theme,
    palette_name = palette_name,
    base_size = base_size,
    save_plots = save_plots,
    save_dir = save_dir,
    plot_width = plot_width,
    plot_height = plot_height
  )

  cat("Best threshold selected:", result$threshold, "\n")

  object@best.model.result[["best_threshold"]] <- result$threshold
  object@best.model.result[["test_threshold_info"]] <- list(
    best_threshold = result,
    test_threshold_metrics = threshold_metrics
  )

  cat("Updating 'Model_data' object...\n")
  cat("The 'Model_data' object has been updated with the following slots:\n")
  cat("- 'best.model.result' slot updated.\n")

  cat("ModelThreshold function completed successfully.\n")

  return(object)
}
